+          {
+            bridge: { bind: "tailnet" },
+            discovery: { wideArea: { enabled: true } },
+          },
+          null,
+          2,
+        ),
+      );
+      console.log("");
+      console.log("Tailscale admin (DNS → Nameservers):");
+      console.log(
+        `- Add nameserver: ${tailnetIPv4 ?? "<this machine's tailnet IPv4>"}`,
+      );
+      console.log(`- Restrict to domain (Split DNS): clawdis.internal`);
